function f(t){return t==null||t===""?"--":Number(t).toLocaleString()}function s(t){return t?new Date(t).toLocaleString():"--"}function u(t){if(!t)return"--";const o=new Date(t).getTime()-Date.now(),n=Math.round(o/6e4);if(Math.abs(n)<60)return`${Math.abs(n)}m ${n<=0?"ago":"from now"}`;const r=Math.round(n/60);if(Math.abs(r)<24)return`${Math.abs(r)}h ${r<=0?"ago":"from now"}`;const a=Math.round(r/24);return`${Math.abs(a)}d ${a<=0?"ago":"from now"}`}export{f as a,s as b,u as f};
